# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

from decimal import Decimal, ROUND_HALF_UP
from typing import Any, Dict, List, Optional


def process_payment(user: Dict[str, Any], cart_items: List[Dict[str, Any]], payment_details: Dict[str, Any]) -> Dict[str, Any]:
    role = str(user.get("role", "basic")).strip().lower()

    discount_map = {
        "basic": Decimal("0.00"),
        "premium": Decimal("0.15"),
        "enterprise": Decimal("0.30"),
    }

    if role not in discount_map:
        raise ValueError(f"Invalid user role: {role}")

    if not isinstance(cart_items, list) or not cart_items:
        raise ValueError("cart_items must be a non-empty list")

    subtotal = Decimal("0.00")
    normalized_items = []

    for item in cart_items:
        if not isinstance(item, dict):
            raise ValueError("Each cart item must be a dictionary")

        quantity = item.get("quantity", 1)
        price = item.get("price")

        if price is None:
            raise ValueError("Each cart item must include a price")

        try:
            quantity = int(quantity)
            price = Decimal(str(price))
        except Exception as e:
            raise ValueError(f"Invalid cart item values: {e}")

        if quantity < 1:
            raise ValueError("Item quantity must be at least 1")
        if price < 0:
            raise ValueError("Item price cannot be negative")

        line_total = (price * quantity).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        subtotal += line_total

        normalized_items.append({
            "name": item.get("name"),
            "quantity": quantity,
            "unit_price": price.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP),
            "line_total": line_total,
        })

    subtotal = subtotal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    discount_rate = discount_map[role]
    discount_amount = (subtotal * discount_rate).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    total = (subtotal - discount_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

    payment_result = _charge_payment(total, payment_details)

    return {
        "status": "success" if payment_result["approved"] else "failed",
        "user_role": role,
        "discount_percentage": int(discount_rate * 100),
        "subtotal": float(subtotal),
        "discount_amount": float(discount_amount),
        "total_charged": float(total if payment_result["approved"] else Decimal("0.00")),
        "items": normalized_items,
        "payment": payment_result,
    }


def _charge_payment(amount: Decimal, payment_details: Dict[str, Any]) -> Dict[str, Any]:
    required_fields = ("card_number", "expiry_month", "expiry_year", "cvv")
    missing = [field for field in required_fields if not payment_details.get(field)]
    if missing:
        return {
            "approved": False,
            "transaction_id": None,
            "amount": float(amount),
            "message": f"Missing payment fields: {', '.join(missing)}",
        }

    card_number = str(payment_details["card_number"]).replace(" ", "")
    if not card_number.isdigit() or len(card_number) < 12:
        return {
            "approved": False,
            "transaction_id": None,
            "amount": float(amount),
            "message": "Invalid card number",
        }

    transaction_id = f"txn_{abs(hash((card_number[-4:], str(amount))))}"
    return {
        "approved": True,
        "transaction_id": transaction_id,
        "amount": float(amount),
        "message": "Payment processed successfully",
    }